// CONFIGURAÇÃO OTIMIZADA PARA EVITAR PERDA DE DADOS
const CHUNK_SIZE = 35; 
const BASE_DELAY = 150; 

const PDFRenderer: React.FC<{ file?: File }> = ({ file }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [pages, setPages] = useState<number[]>([]);
    const [pdfInstance, setPdfInstance] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!file) {
            setError("Arquivo original não disponível para visualização.");
            return;
        }

        const loadPDF = async () => {
            const pdfjsLib = (window as any).pdfjsLib;
            if (!pdfjsLib) {
                setError("Biblioteca PDF não carregada.");
                return;
            }
            try {
                const buffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument(new Uint8Array(buffer));
                const pdf = await loadingTask.promise;
                setPdfInstance(pdf);
                setPages(Array.from({ length: pdf.numPages }, (_, i) => i + 1));
            } catch (err: any) { 
                console.error("PDF Load error:", err); 
                setError("Erro ao renderizar PDF: " + (err.message || 'Desconhecido'));
            }
        };
        loadPDF();
    }, [file]);

    if (error) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center">
                <XMarkIcon className="w-10 h-10 mb-2 opacity-50" />
                <p className="text-xs">{error}</p>
                <p className="text-[10px] mt-2">Use o modo "Tabela" para ver os dados extraídos.</p>
            </div>
        );
    }

    const PageCanvas: React.FC<{ pageNum: number, pdf: any }> = ({ pageNum, pdf }) => {
        const canvasRef = useRef<HTMLCanvasElement>(null);
        useEffect(() => {
            const render = async () => {
                if (!pdf || !canvasRef.current) return;
                try {
                    const page = await pdf.getPage(pageNum);
                    const viewport = page.getViewport({ scale: 1.5 });
                    const canvas = canvasRef.current;
                    const context = canvas.getContext('2d');
                    if (context) {
                        canvas.height = viewport.height;
                        canvas.width = viewport.width;
                        await page.render({ canvasContext: context, viewport }).promise;
                    }
                } catch (e) { console.error(e); }
            };
            render();
        }, [pageNum, pdf]);
        return (
            <div className="bg-white p-2 shadow-xl border border-slate-200 mb-6 rounded-sm max-w-full overflow-hidden">
                <canvas ref={canvasRef} className="w-full h-auto" />
            </div>
        );
    };

    return (
        <div ref={containerRef} className="p-8 flex flex-col items-center bg-slate-200 dark:bg-slate-950/50 min-h-full">
            {pages.map(p => <PageCanvas key={p} pageNum={p} pdf={pdfInstance} />)}
            {pages.length === 0 && !error && (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                    <ArrowPathIcon className="w-10 h-10 animate-spin mb-4" />
                    <p className="text-xs font-bold uppercase tracking-widest">Processando visualização...</p>
                </div>
            )}
        </div>
    );
};

interface TreatedRow {
    id: string;
    originalIndex?: number;
    date: string;
    name: string;
    amount: string;
    type?: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted' | 'processing' | 'invalid';
}

type ColumnType = 'ignore' | 'date' | 'description' | 'amount' | 'type';

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel;
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
}> = ({ onClose, initialFile, initialModel, onSuccess }) => {
    const { showToast } = useUI();
    const { fetchModels } = useContext(AppContext);
    const { user } = useAuth();

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [isSavingModel, setIsSavingModel] = useState(false);
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('cells');
    const [columnMapping, setColumnMapping] = useState<Record<number, ColumnType>>({});
    const [skipRowsStart, setSkipRowsStart] = useState(0);
    const [modelName, setModelName] = useState('');

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);

    // 1. Carregamento Inicial do Arquivo
    useEffect(() => {
        if (!initialFile) return;
        const content = initialFile.content || '';
        const lines = content.split(/\r?\n/).filter((l: string) => l.trim().length > 0);

        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            if (initialModel?.fingerprint?.delimiter) delimiter = initialModel.fingerprint.delimiter;
            else if (!isPdf) delimiter = detectDelimiter(lines[0]);

            const parsed = lines.map((l: string) => l.split(delimiter));
            setRawRows(parsed);

            // Se for modo refinamento (initialModel presente), carrega o mapeamento
            if (initialModel) {
                setModelName(initialModel.name);
                if (initialModel.mapping) {
                    setColumnMapping({
                        [initialModel.mapping.dateColumnIndex]: 'date',
                        [initialModel.mapping.descriptionColumnIndex]: 'description',
                        [initialModel.mapping.amountColumnIndex]: 'amount',
                        ...(initialModel.mapping.typeColumnIndex !== undefined ? { [initialModel.mapping.typeColumnIndex]: 'type' } : {})
                    });
                    setSkipRowsStart(initialModel.mapping.skipRowsStart || 0);
                }
            } else {
                setModelName(initialFile.fileName || 'Novo Modelo');
            }
        }
    }, [initialFile, initialModel, isPdf]);

    // 2. Auto-detecção de Colunas e Execução Inicial
    useEffect(() => {
        if (rawRows.length > 0 && !initialModel) {
            // Tenta detectar colunas automaticamente se ainda não foram mapeadas
            if (Object.keys(columnMapping).length === 0) {
                const dateIdx = DateResolver.identifyDateColumn(rawRows);
                const amountIdx = AmountResolver.identifyAmountColumn(rawRows, [dateIdx]);
                const nameIdx = NameResolver.identifyNameColumn(rawRows, [dateIdx, amountIdx]);
                const typeIdx = TypeResolver.identifyTypeColumn(rawRows, [dateIdx, amountIdx, nameIdx]);

                const newMapping: Record<number, ColumnType> = {};
                if (dateIdx !== -1) newMapping[dateIdx] = 'date';
                if (amountIdx !== -1) newMapping[amountIdx] = 'amount';
                if (nameIdx !== -1) newMapping[nameIdx] = 'description';
                if (typeIdx !== -1) newMapping[typeIdx] = 'type';

                setColumnMapping(newMapping);
            }
        }
    }, [rawRows, initialModel]);

    const handleColumnClick = (colIndex: number) => {
        setColumnMapping(prev => {
            const next = { ...prev };
            // Cycle: ignore -> date -> description -> amount -> type -> ignore
            const current = next[colIndex] || 'ignore';
            if (current === 'ignore') next[colIndex] = 'date';
            else if (current === 'date') next[colIndex] = 'description';
            else if (current === 'description') next[colIndex] = 'amount';
            else if (current === 'amount') next[colIndex] = 'type';
            else delete next[colIndex];

            // Ensure only one of each primary type
            if (next[colIndex] && next[colIndex] !== 'ignore') {
                Object.keys(next).forEach(k => {
                    const key = parseInt(k);
                    if (key !== colIndex && next[key] === next[colIndex]) {
                        delete next[key];
                    }
                });
            }
            return next;
        });
    };

    const getColumnColor = (type?: ColumnType) => {
        switch (type) {
            case 'date': return 'bg-blue-100 text-blue-700 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-800';
            case 'description': return 'bg-purple-100 text-purple-700 border-purple-200 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-800';
            case 'amount': return 'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-800';
            case 'type': return 'bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-900/30 dark:text-amber-300 dark:border-amber-800';
            default: return 'bg-slate-50 text-slate-400 border-slate-200 dark:bg-slate-800 dark:text-slate-500 dark:border-slate-700';
        }
    };

    const handleSave = async () => {
        if (!user) return;

        // Validação básica
        const hasDate = Object.values(columnMapping).includes('date');
        const hasDesc = Object.values(columnMapping).includes('description');
        const hasAmount = Object.values(columnMapping).includes('amount');

