// CONFIGURAÇÃO OTIMIZADA PARA EVITAR PERDA DE DADOS
const CHUNK_SIZE = 35; 
const BASE_DELAY = 150; 

const PDFRenderer: React.FC<{ file?: File }> = ({ file }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [pages, setPages] = useState<number[]>([]);
    const [pdfInstance, setPdfInstance] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!file) {
            setError("Arquivo original não disponível para visualização.");
            return;
        }

        const loadPDF = async () => {
            const pdfjsLib = (window as any).pdfjsLib;
            if (!pdfjsLib) {
                setError("Biblioteca PDF não carregada.");
                return;
            }
            try {
                const buffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument(new Uint8Array(buffer));
                const pdf = await loadingTask.promise;
                setPdfInstance(pdf);
                setPages(Array.from({ length: pdf.numPages }, (_, i) => i + 1));
            } catch (err: any) { 
                console.error("PDF Load error:", err); 
                setError("Erro ao renderizar PDF: " + (err.message || 'Desconhecido'));
            }
        };
        loadPDF();
    }, [file]);

    if (error) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center">
                <XMarkIcon className="w-10 h-10 mb-2 opacity-50" />
                <p className="text-xs">{error}</p>
                <p className="text-[10px] mt-2">Use o modo "Tabela" para ver os dados extraídos.</p>
            </div>
        );
    }

    const PageCanvas: React.FC<{ pageNum: number, pdf: any }> = ({ pageNum, pdf }) => {
        const canvasRef = useRef<HTMLCanvasElement>(null);
        useEffect(() => {
            const render = async () => {
                if (!pdf || !canvasRef.current) return;
                try {
                    const page = await pdf.getPage(pageNum);
                    const viewport = page.getViewport({ scale: 1.5 });
                    const canvas = canvasRef.current;
                    const context = canvas.getContext('2d');
                    if (context) {
                        canvas.height = viewport.height;
                        canvas.width = viewport.width;
                        await page.render({ canvasContext: context, viewport }).promise;
                    }
                } catch (e) { console.error(e); }
            };
            render();
        }, [pageNum, pdf]);
        return (
            <div className="bg-white p-2 shadow-xl border border-slate-200 mb-6 rounded-sm max-w-full overflow-hidden">
                <canvas ref={canvasRef} className="w-full h-auto" />
            </div>
        );
    };

    return (
        <div ref={containerRef} className="p-8 flex flex-col items-center bg-slate-200 dark:bg-slate-950/50 min-h-full">
            {pages.map(p => <PageCanvas key={p} pageNum={p} pdf={pdfInstance} />)}
            {pages.length === 0 && !error && (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                    <ArrowPathIcon className="w-10 h-10 animate-spin mb-4" />
                    <p className="text-xs font-bold uppercase tracking-widest">Processando visualização...</p>
                </div>
            )}
        </div>
    );
};

interface TreatedRow {
    id: string;
    originalIndex?: number;
    date: string;
    name: string;
    amount: string;
    type?: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted' | 'processing' | 'invalid';
}

type ColumnType = 'ignore' | 'date' | 'description' | 'amount' | 'type';

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel;
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
}> = ({ onClose, initialFile, initialModel, onSuccess }) => {
    const { showToast } = useUI();
    const { fetchModels } = useContext(AppContext);
    const { user } = useAuth();

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [isSavingModel, setIsSavingModel] = useState(false);
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('cells');
    const [columnMapping, setColumnMapping] = useState<Record<number, ColumnType>>({});
    const [skipRowsStart, setSkipRowsStart] = useState(0);
    const [modelName, setModelName] = useState('');

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);

    // 1. Carregamento Inicial do Arquivo
    useEffect(() => {
        if (!initialFile) return;
        const content = initialFile.content || '';
        const lines = content.split(/\r?\n/).filter((l: string) => l.trim().length > 0);

        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            if (initialModel?.fingerprint?.delimiter) delimiter = initialModel.fingerprint.delimiter;
            else if (!isPdf) delimiter = detectDelimiter(lines[0]);

            const parsed = lines.map((l: string) => l.split(delimiter));
            setRawRows(parsed);

            // Se for modo refinamento (initialModel presente), carrega o mapeamento
            if (initialModel) {
                setModelName(initialModel.name);
                if (initialModel.mapping) {
                    setColumnMapping({
                        [initialModel.mapping.dateColumnIndex]: 'date',
                        [initialModel.mapping.descriptionColumnIndex]: 'description',
                        [initialModel.mapping.amountColumnIndex]: 'amount',
                        ...(initialModel.mapping.typeColumnIndex !== undefined ? { [initialModel.mapping.typeColumnIndex]: 'type' } : {})
                    });
                    setSkipRowsStart(initialModel.mapping.skipRowsStart || 0);
                }
            } else {
                setModelName(initialFile.fileName || 'Novo Modelo');
            }
        }
    }, [initialFile, initialModel, isPdf]);

    // 2. Auto-detecção de Colunas e Execução Inicial
    useEffect(() => {
        if (rawRows.length > 0 && !initialModel) {
            // Tenta detectar colunas automaticamente se ainda não foram mapeadas
            if (Object.keys(columnMapping).length === 0) {
                const dateIdx = DateResolver.identifyDateColumn(rawRows);
                const amountIdx = AmountResolver.identifyAmountColumn(rawRows, [dateIdx]);
                const nameIdx = NameResolver.identifyNameColumn(rawRows, [dateIdx, amountIdx]);
                const typeIdx = TypeResolver.identifyTypeColumn(rawRows, [dateIdx, amountIdx, nameIdx]);

                const newMapping: Record<number, ColumnType> = {};
                if (dateIdx !== -1) newMapping[dateIdx] = 'date';
                if (amountIdx !== -1) newMapping[amountIdx] = 'amount';
                if (nameIdx !== -1) newMapping[nameIdx] = 'description';
                if (typeIdx !== -1) newMapping[typeIdx] = 'type';

                setColumnMapping(newMapping);
            }
        }
    }, [rawRows, initialModel]);

    const handleColumnClick = (colIndex: number) => {
        setColumnMapping(prev => {
            const next = { ...prev };
            // Cycle: ignore -> date -> description -> amount -> type -> ignore
            const current = next[colIndex] || 'ignore';
            if (current === 'ignore') next[colIndex] = 'date';
            else if (current === 'date') next[colIndex] = 'description';
            else if (current === 'description') next[colIndex] = 'amount';
            else if (current === 'amount') next[colIndex] = 'type';
            else delete next[colIndex];

            // Ensure only one of each primary type
            if (next[colIndex] && next[colIndex] !== 'ignore') {
                Object.keys(next).forEach(k => {
                    const key = parseInt(k);
                    if (key !== colIndex && next[key] === next[colIndex]) {
                        delete next[key];
                    }
                });
            }
            return next;
        });
    };

    const getColumnColor = (type?: ColumnType) => {
        switch (type) {
            case 'date': return 'bg-blue-100 text-blue-700 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-800';
            case 'description': return 'bg-purple-100 text-purple-700 border-purple-200 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-800';
            case 'amount': return 'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-800';
            case 'type': return 'bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-900/30 dark:text-amber-300 dark:border-amber-800';
            default: return 'bg-slate-50 text-slate-400 border-slate-200 dark:bg-slate-800 dark:text-slate-500 dark:border-slate-700';
        }
    };

    const handleSave = async () => {
        if (!user) return;

        // Validação básica
        const hasDate = Object.values(columnMapping).includes('date');
        const hasDesc = Object.values(columnMapping).includes('description');
        const hasAmount = Object.values(columnMapping).includes('amount');

        if (!hasDate || !hasDesc || !hasAmount) {
            showToast("Mapeie pelo menos Data, Descrição e Valor.", "error");
            return;
        }

        setIsSavingModel(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (!fingerprint) throw new Error("Falha ao gerar impressão digital do arquivo.");

            // Find indexes from mapping
            const mappingEntries = Object.entries(columnMapping);
            const dateIdx = parseInt(mappingEntries.find(([, t]) => t === 'date')?.[0] || '0');
            const descIdx = parseInt(mappingEntries.find(([, t]) => t === 'description')?.[0] || '0');
            const amountIdx = parseInt(mappingEntries.find(([, t]) => t === 'amount')?.[0] || '0');
            const typeIdxEntry = mappingEntries.find(([, t]) => t === 'type');
            const typeIdx = typeIdxEntry ? parseInt(typeIdxEntry[0]) : undefined;

            const newModel: Omit<FileModel, 'id' | 'createdAt'> = {
                name: modelName,
                user_id: user.id,
                version: (initialModel?.version || 0) + 1,
                lineage_id: initialModel?.lineage_id || `lin-${Date.now()}`,
                is_active: true,
                fingerprint,
                mapping: {
                    dateColumnIndex: dateIdx,
                    descriptionColumnIndex: descIdx,
                    amountColumnIndex: amountIdx,
                    typeColumnIndex: typeIdx,
                    skipRowsStart: skipRowsStart,
                    skipRowsEnd: 0,
                    decimalSeparator: ',', // Padrão BR assumido
                    thousandsSeparator: '.'
                },
                parsingRules: {
                    ignoredKeywords: initialModel?.parsingRules?.ignoredKeywords || [],
                    rowFilters: []
                },
                snippet: extractSnippet(initialFile.content)
            };

            const saved = await modelService.saveModel(newModel);
            if (saved) {
                await fetchModels();
                showToast("Modelo salvo com sucesso!", "success");

                // Processa os dados para retornar
                const processed = processFileContent(initialFile.content, initialFile.fileName, [saved]);
                if (onSuccess) onSuccess(saved, processed.transactions);
                onClose();
            } else {
                showToast("Erro ao salvar modelo.", "error");
            }
        } catch (e: any) {
            console.error(e);
            showToast("Erro ao salvar: " + e.message, "error");
        } finally {
            setIsSavingModel(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[150] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white dark:bg-[#0F172A] w-full max-w-6xl h-[90vh] rounded-[2rem] shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in">

                {/* Header */}
                <div className="px-6 py-4 bg-slate-50 dark:bg-slate-900/80 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="p-2.5 bg-indigo-500/10 rounded-xl text-indigo-500 border border-indigo-500/20">
                            <WrenchScrewdriverIcon className="w-5 h-5" />
                        </div>
                        <div>
                            <h3 className="text-lg font-black text-slate-800 dark:text-white tracking-tight">Laboratório de Arquivos</h3>
                            <div className="flex items-center gap-2 text-xs text-slate-500 dark:text-slate-400">
                                <span className="font-mono">{initialFile?.fileName}</span>
                                <span>•</span>
                                <span className="uppercase font-bold text-[10px]">{rawRows.length} linhas detectadas</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        <input 
                            type="text" 
                            value={modelName}
                            onChange={(e) => setModelName(e.target.value)}
                            placeholder="Nome do Modelo"
                            className="bg-transparent border-b border-slate-300 dark:border-slate-600 px-2 py-1 text-sm font-bold text-slate-700 dark:text-slate-200 focus:border-indigo-500 outline-none w-48 text-right"
                        />
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>
                </div>

                {/* Main Workspace */}
                <div className="flex-1 flex overflow-hidden">

                    {/* Left Panel: Preview & Mapping */}
                    <div className="flex-1 overflow-auto bg-slate-100 dark:bg-black/20 p-4 custom-scrollbar relative">
                        {isPdf && viewMode === 'original' ? (
                            <div className="h-full overflow-auto rounded-xl border border-slate-200 dark:border-slate-700 shadow-inner">
                                <PDFRenderer file={initialFile.rawFile} />
                            </div>
                        ) : (
                            <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
                                <div className="overflow-x-auto">
                                    <table className="w-full text-xs text-left border-collapse">
                                        <thead>
                                            <tr>
                                                <th className="p-2 w-10 bg-slate-50 dark:bg-slate-800 border-b border-r border-slate-200 dark:border-slate-700 text-center font-mono text-slate-400">#</th>
                                                {rawRows[0]?.map((_, colIndex) => {
                                                    const type = columnMapping[colIndex];
                                                    return (
                                                        <th key={colIndex} className="p-1 min-w-[120px] bg-slate-50 dark:bg-slate-800 border-b border-r border-slate-200 dark:border-slate-700">
                                                            <button 
                                                                onClick={() => handleColumnClick(colIndex)}
                                                                className={`w-full py-1.5 px-2 rounded text-[10px] font-bold uppercase tracking-wide border transition-all ${getColumnColor(type)}`}
                                                            >
                                                                {type ? type : 'Ignorar'}
                                                            </button>
                                                        </th>
                                                    );
                                                })}
                                            </tr>
                                        </thead>
                                        <tbody className="font-mono text-slate-600 dark:text-slate-300">
                                            {rawRows.slice(0, 50).map((row, rowIndex) => (
                                                <tr key={rowIndex} className={`hover:bg-blue-50/50 dark:hover:bg-blue-900/10 ${rowIndex < skipRowsStart ? 'opacity-40 bg-slate-50 dark:bg-black/40' : ''}`}>
                                                    <td 
                                                        className="p-2 border-b border-r border-slate-100 dark:border-slate-800 text-center text-[10px] text-slate-400 cursor-pointer hover:text-brand-blue"
                                                        onClick={() => setSkipRowsStart(rowIndex)}
                                                        title="Começar importação a partir desta linha"
                                                    >
                                                        {rowIndex + 1}
                                                    </td>
                                                    {row.map((cell, colIndex) => (
                                                        <td key={colIndex} className="p-2 border-b border-r border-slate-100 dark:border-slate-800 truncate max-w-[200px]" title={cell}>
                                                            {cell}
                                                        </td>
                                                    ))}
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                                {rawRows.length > 50 && (
                                    <div className="p-2 text-center text-[10px] text-slate-400 bg-slate-50 dark:bg-slate-800 border-t border-slate-200 dark:border-slate-700">
                                        Exibindo as primeiras 50 linhas de {rawRows.length}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>

                    {/* Right Panel: Controls */}
                    <div className="w-80 bg-white dark:bg-slate-900 border-l border-slate-200 dark:border-slate-700 flex flex-col shrink-0 z-10">
                        <div className="p-5 border-b border-slate-100 dark:border-slate-800">
                            <h4 className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-4">Configuração</h4>

                            <div className="space-y-4">
                                <div>
                                    <label className="block text-[10px] font-bold text-slate-400 mb-1.5 uppercase">Início dos Dados</label>
                                    <div className="flex items-center gap-2">
                                        <button onClick={() => setSkipRowsStart(Math.max(0, skipRowsStart - 1))} className="w-8 h-8 rounded-lg bg-slate-100 dark:bg-slate-800 flex items-center justify-center hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300">-</button>
                                        <div className="flex-1 text-center font-mono font-bold text-slate-700 dark:text-white bg-slate-50 dark:bg-black/20 py-1.5 rounded-lg border border-slate-200 dark:border-slate-800">
                                            Linha {skipRowsStart + 1}
                                        </div>
                                        <button onClick={() => setSkipRowsStart(skipRowsStart + 1)} className="w-8 h-8 rounded-lg bg-slate-100 dark:bg-slate-800 flex items-center justify-center hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300">+</button>
                                    </div>
                                </div>

                                {isPdf && (
                                    <div>
                                        <label className="block text-[10px] font-bold text-slate-400 mb-1.5 uppercase">Modo de Visualização</label>
                                        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-lg">
                                            <button 
                                                onClick={() => setViewMode('cells')}
                                                className={`flex-1 py-1.5 rounded-md text-[10px] font-bold transition-all ${viewMode === 'cells' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                                            >
                                                Tabela
                                            </button>
                                            <button 
                                                onClick={() => setViewMode('original')}
                                                className={`flex-1 py-1.5 rounded-md text-[10px] font-bold transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                                            >
                                                Original
                                            </button>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="p-5 flex-1 overflow-y-auto">
                            <div className="p-4 bg-amber-50 dark:bg-amber-900/10 rounded-xl border border-amber-100 dark:border-amber-800/50 mb-4">
                                <div className="flex items-start gap-2">
                                    <SparklesIcon className="w-4 h-4 text-amber-500 mt-0.5" />
                                    <div>
                                        <p className="text-xs font-bold text-amber-700 dark:text-amber-400">Dica Inteligente</p>
                                        <p className="text-[10px] text-amber-600 dark:text-amber-500 mt-1 leading-snug">
                                            Clique nos cabeçalhos da tabela para definir o tipo de coluna (Data, Descrição, Valor, Tipo).
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="p-5 border-t border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50">
                            <button
                                onClick={handleSave}
                                disabled={isSavingModel}
                                className="w-full flex items-center justify-center gap-2 py-3 bg-gradient-to-r from-emerald-600 to-teal-500 hover:from-emerald-500 hover:to-teal-400 text-white rounded-xl font-bold text-xs uppercase shadow-lg shadow-emerald-500/20 hover:-translate-y-0.5 transition-all disabled:opacity-70 disabled:cursor-not-allowed"
                            >
                                {isSavingModel ? (
                                    <>
                                        <ArrowPathIcon className="w-4 h-4 animate-spin" />
                                        Salvando...
                                    </>
                                ) : (
                                    <>
                                        <FloppyDiskIcon className="w-4 h-4" />
                                        Salvar e Processar
                                    </>
                                )}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useRef, useMemo, useContext } from 'react';
import { createPortal } from 'react-dom';
import { 
    XMarkIcon, 
    TableCellsIcon, 
    ArrowPathIcon, 
    BrainIcon,
    AdjustmentsHorizontalIcon,
    SparklesIcon,
    BoltIcon,
    ClockIcon,
    CursorArrowRaysIcon,
    CodeBracketSquareIcon,
    CheckCircleIcon,
    FloppyDiskIcon,
    WrenchScrewdriverIcon
} from '../Icons';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext';
import { useAuth } from '../../contexts/AuthContext';
import { performInitialInference } from '../../services/geminiService';
import { cleanTransactionDescriptionForDisplay, extractSnippet, processFileContent } from '../../services/processingService';
import { detectDelimiter, generateFingerprint } from '../../core/processors/Fingerprinter';
import { DateResolver } from '../../core/processors/DateResolver';
import { AmountResolver } from '../../core/processors/AmountResolver';
import { NameResolver } from '../../core/processors/NameResolver';
import { TypeResolver } from '../../core/processors/TypeResolver';
import { FileModel, Transaction } from '../../types';
import { modelService } from '../../services/modelService';

// CONFIGURAÇÃO OTIMIZADA PARA EVITAR PERDA DE DADOS
const CHUNK_SIZE = 35; 
const BASE_DELAY = 150; 

const PDFRenderer: React.FC<{ file?: File }> = ({ file }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [pages, setPages] = useState<number[]>([]);
    const [pdfInstance, setPdfInstance] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!file) {
            // Se não houver arquivo (ex: modo refinamento), não tenta carregar
            return;
        }

        const loadPDF = async () => {
            const pdfjsLib = (window as any).pdfjsLib;
            if (!pdfjsLib) {
                setError("Biblioteca PDF não carregada. Recarregue a página.");
                return;
            }
            try {
                const buffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument(new Uint8Array(buffer));
                const pdf = await loadingTask.promise;
                setPdfInstance(pdf);
                setPages(Array.from({ length: pdf.numPages }, (_, i) => i + 1));
            } catch (err: any) { 
                console.error("PDF Load error:", err); 
                setError("Erro ao renderizar PDF. Use a visualização de tabela.");
            }
        };
        loadPDF();
    }, [file]);

    if (!file) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center">
                <TableCellsIcon className="w-12 h-12 mb-3 opacity-20" />
                <p className="text-xs font-bold">Visualização Original Indisponível</p>
                <p className="text-[10px] mt-1 opacity-70">Apenas os dados extraídos estão disponíveis.</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center">
                <XMarkIcon className="w-10 h-10 mb-2 opacity-50" />
                <p className="text-xs">{error}</p>
            </div>
        );
    }

    const PageCanvas: React.FC<{ pageNum: number, pdf: any }> = ({ pageNum, pdf }) => {
        const canvasRef = useRef<HTMLCanvasElement>(null);
        useEffect(() => {
            const render = async () => {
                if (!pdf || !canvasRef.current) return;
                try {
                    const page = await pdf.getPage(pageNum);
                    const viewport = page.getViewport({ scale: 1.5 });
                    const canvas = canvasRef.current;
                    const context = canvas.getContext('2d');
                    if (context) {
                        canvas.height = viewport.height;
                        canvas.width = viewport.width;
                        await page.render({ canvasContext: context, viewport }).promise;
                    }
                } catch (e) { console.error(e); }
            };
            render();
        }, [pageNum, pdf]);
        return (
            <div className="bg-white p-2 shadow-xl border border-slate-200 mb-6 rounded-sm max-w-full overflow-hidden">
                <canvas ref={canvasRef} className="w-full h-auto" />
            </div>
        );
    };

    return (
        <div ref={containerRef} className="p-8 flex flex-col items-center bg-slate-200 dark:bg-slate-950/50 min-h-full">
            {pages.map(p => <PageCanvas key={p} pageNum={p} pdf={pdfInstance} />)}
            {pages.length === 0 && !error && (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                    <ArrowPathIcon className="w-10 h-10 animate-spin mb-4" />
                    <p className="text-xs font-bold uppercase tracking-widest">Processando visualização...</p>
                </div>
            )}
        </div>
    );
};

interface TreatedRow {
    id: string;
    originalIndex?: number;
    date: string;
    name: string;
    amount: string;
    type?: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted' | 'processing' | 'invalid';
}

type ColumnType = 'ignore' | 'date' | 'description' | 'amount' | 'type';

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel;
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
}> = ({ onClose, initialFile, initialModel, onSuccess }) => {
    const { showToast } = useUI();
    const { fetchModels } = useContext(AppContext);
    const { user } = useAuth();

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [isSavingModel, setIsSavingModel] = useState(false);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const hasRawFile = !!initialFile?.rawFile;

    // Se tem rawFile e é PDF, tenta mostrar o original. Se não, força tabela.
    const [viewMode, setViewMode] = useState<'original' | 'cells'>(isPdf && hasRawFile ? 'original' : 'cells');

    const [columnMapping, setColumnMapping] = useState<Record<number, ColumnType>>({});
    const [skipRowsStart, setSkipRowsStart] = useState(0);
    const [modelName, setModelName] = useState('');

    // 1. Carregamento Inicial do Arquivo
    useEffect(() => {
        if (!initialFile) return;
        const content = initialFile.content || '';
        const lines = content.split(/\r?\n/).filter((l: string) => l.trim().length > 0);

        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            if (initialModel?.fingerprint?.delimiter) delimiter = initialModel.fingerprint.delimiter;
            else if (!isPdf) delimiter = detectDelimiter(lines[0]);

            const parsed = lines.map((l: string) => l.split(delimiter));
            setRawRows(parsed);

            // Se for modo refinamento (initialModel presente), carrega o mapeamento
            if (initialModel) {
                setModelName(initialModel.name);
                if (initialModel.mapping) {
                    setColumnMapping({
                        [initialModel.mapping.dateColumnIndex]: 'date',
                        [initialModel.mapping.descriptionColumnIndex]: 'description',
                        [initialModel.mapping.amountColumnIndex]: 'amount',
                        ...(initialModel.mapping.typeColumnIndex !== undefined ? { [initialModel.mapping.typeColumnIndex]: 'type' } : {})
                    });
                    setSkipRowsStart(initialModel.mapping.skipRowsStart || 0);
                }
            } else {
                setModelName(initialFile.fileName || 'Novo Modelo');
            }
        }
    }, [initialFile, initialModel, isPdf]);

    // 2. Auto-detecção de Colunas e Execução Inicial
    useEffect(() => {
        if (rawRows.length > 0 && !initialModel) {
            // Tenta detectar colunas automaticamente se ainda não foram mapeadas
            if (Object.keys(columnMapping).length === 0) {
                const dateIdx = DateResolver.identifyDateColumn(rawRows);
                const amountIdx = AmountResolver.identifyAmountColumn(rawRows, [dateIdx]);
                const nameIdx = NameResolver.identifyNameColumn(rawRows, [dateIdx, amountIdx]);
                const typeIdx = TypeResolver.identifyTypeColumn(rawRows, [dateIdx, amountIdx, nameIdx]);

                const newMapping: Record<number, ColumnType> = {};
                if (dateIdx !== -1) newMapping[dateIdx] = 'date';
                if (amountIdx !== -1) newMapping[amountIdx] = 'amount';
                if (nameIdx !== -1) newMapping[nameIdx] = 'description';
                if (typeIdx !== -1) newMapping[typeIdx] = 'type';

                setColumnMapping(newMapping);
            }
        }
    }, [rawRows, initialModel]);

    const handleColumnClick = (colIndex: number) => {
        setColumnMapping(prev => {
            const next = { ...prev };
            // Cycle: ignore -> date -> description -> amount -> type -> ignore
            const current = next[colIndex] || 'ignore';
            if (current === 'ignore') next[colIndex] = 'date';
            else if (current === 'date') next[colIndex] = 'description';
            else if (current === 'description') next[colIndex] = 'amount';
            else if (current === 'amount') next[colIndex] = 'type';
            else delete next[colIndex];

            // Ensure only one of each primary type
            if (next[colIndex] && next[colIndex] !== 'ignore') {
                Object.keys(next).forEach(k => {
                    const key = parseInt(k);
                    if (key !== colIndex && next[key] === next[colIndex]) {
                        delete next[key];
                    }
                });
            }
            return next;
        });
    };

    const getColumnColor = (type?: ColumnType) => {
        switch (type) {
            case 'date': return 'bg-blue-100 text-blue-700 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-800';
            case 'description': return 'bg-purple-100 text-purple-700 border-purple-200 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-800';
            case 'amount': return 'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-800';
            case 'type': return 'bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-900/30 dark:text-amber-300 dark:border-amber-800';
            default: return 'bg-slate-50 text-slate-400 border-slate-200 dark:bg-slate-800 dark:text-slate-500 dark:border-slate-700';
        }
    };

    const handleSave = async () => {
        if (!user) return;

        // Validação básica
        const hasDate = Object.values(columnMapping).includes('date');
        const hasDesc = Object.values(columnMapping).includes('description');
        const hasAmount = Object.values(columnMapping).includes('amount');

        if (!hasDate || !hasDesc || !hasAmount) {
            showToast("Mapeie pelo menos Data, Descrição e Valor.", "error");
            return;
        }

        setIsSavingModel(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (!fingerprint) throw new Error("Falha ao gerar impressão digital do arquivo.");

            // Find indexes from mapping
            const mappingEntries = Object.entries(columnMapping);
            const dateIdx = parseInt(mappingEntries.find(([, t]) => t === 'date')?.[0] || '0');
            const descIdx = parseInt(mappingEntries.find(([, t]) => t === 'description')?.[0] || '0');
            const amountIdx = parseInt(mappingEntries.find(([, t]) => t === 'amount')?.[0] || '0');
            const typeIdxEntry = mappingEntries.find(([, t]) => t === 'type');
            const typeIdx = typeIdxEntry ? parseInt(typeIdxEntry[0]) : undefined;

            const newModel: Omit<FileModel, 'id' | 'createdAt'> = {
                name: modelName,
                user_id: user.id,
                version: (initialModel?.version || 0) + 1,
                lineage_id: initialModel?.lineage_id || `lin-${Date.now()}`,
                is_active: true,
                fingerprint,
                mapping: {
                    dateColumnIndex: dateIdx,
                    descriptionColumnIndex: descIdx,
                    amountColumnIndex: amountIdx,
                    typeColumnIndex: typeIdx,
                    skipRowsStart: skipRowsStart,
                    skipRowsEnd: 0,
                    decimalSeparator: ',', // Padrão BR assumido
                    thousandsSeparator: '.'
                },
                parsingRules: {
                    ignoredKeywords: initialModel?.parsingRules?.ignoredKeywords || [],
                    rowFilters: []
                },
                snippet: extractSnippet(initialFile.content)
            };

            const saved = await modelService.saveModel(newModel);
            if (saved) {
                await fetchModels();
                showToast("Modelo salvo com sucesso!", "success");

                // Processa os dados para retornar
                const processed = processFileContent(initialFile.content, initialFile.fileName, [saved]);
                if (onSuccess) onSuccess(saved, processed.transactions);
                onClose();
            } else {
                showToast("Erro ao salvar modelo.", "error");
            }
        } catch (e: any) {
            console.error(e);
            showToast("Erro ao salvar: " + e.message, "error");
        } finally {
            setIsSavingModel(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[150] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white dark:bg-[#0F172A] w-full max-w-6xl h-[90vh] rounded-[2rem] shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in">

                {/* Header */}
                <div className="px-6 py-4 bg-slate-50 dark:bg-slate-900/80 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="p-2.5 bg-indigo-500/10 rounded-xl text-indigo-500 border border-indigo-500/20">
                            <WrenchScrewdriverIcon className="w-5 h-5" />
                        </div>
                        <div>
                            <h3 className="text-lg font-black text-slate-800 dark:text-white tracking-tight">Laboratório de Arquivos</h3>
                            <div className="flex items-center gap-2 text-xs text-slate-500 dark:text-slate-400">
                                <span className="font-mono">{initialFile?.fileName}</span>
                                <span>•</span>
                                <span className="uppercase font-bold text-[10px]">{rawRows.length} linhas detectadas</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        <input 
                            type="text" 
                            value={modelName}
                            onChange={(e) => setModelName(e.target.value)}
                            placeholder="Nome do Modelo"
                            className="bg-transparent border-b border-slate-300 dark:border-slate-600 px-2 py-1 text-sm font-bold text-slate-700 dark:text-slate-200 focus:border-indigo-500 outline-none w-48 text-right"
                        />
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>
                </div>

                {/* Main Workspace - 2 Columns */}
                <div className="flex-1 flex flex-row overflow-hidden">

                    {/* Left Panel: Preview & Mapping (Flex-1) */}
                    <div className="flex-1 overflow-auto bg-slate-100 dark:bg-black/20 p-4 custom-scrollbar relative">
                        {isPdf && viewMode === 'original' && hasRawFile ? (
                            <div className="h-full overflow-auto rounded-xl border border-slate-200 dark:border-slate-700 shadow-inner">
                                <PDFRenderer file={initialFile.rawFile} />
                            </div>
                        ) : (
                            <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
                                <div className="overflow-x-auto">
                                    <table className="w-full text-xs text-left border-collapse">
                                        <thead>
                                            <tr>
                                                <th className="p-2 w-10 bg-slate-50 dark:bg-slate-800 border-b border-r border-slate-200 dark:border-slate-700 text-center font-mono text-slate-400">#</th>
                                                {rawRows[0]?.map((_, colIndex) => {
                                                    const type = columnMapping[colIndex];
                                                    return (
                                                        <th key={colIndex} className="p-1 min-w-[120px] bg-slate-50 dark:bg-slate-800 border-b border-r border-slate-200 dark:border-slate-700">
                                                            <button 
                                                                onClick={() => handleColumnClick(colIndex)}
                                                                className={`w-full py-1.5 px-2 rounded text-[10px] font-bold uppercase tracking-wide border transition-all ${getColumnColor(type)}`}
                                                            >
                                                                {type ? type : 'Ignorar'}
                                                            </button>
                                                        </th>
                                                    );
                                                })}
                                            </tr>
                                        </thead>
                                        <tbody className="font-mono text-slate-600 dark:text-slate-300">
                                            {rawRows.slice(0, 50).map((row, rowIndex) => (
                                                <tr key={rowIndex} className={`hover:bg-blue-50/50 dark:hover:bg-blue-900/10 ${rowIndex < skipRowsStart ? 'opacity-40 bg-slate-50 dark:bg-black/40' : ''}`}>
                                                    <td 
                                                        className="p-2 border-b border-r border-slate-100 dark:border-slate-800 text-center text-[10px] text-slate-400 cursor-pointer hover:text-brand-blue"
                                                        onClick={() => setSkipRowsStart(rowIndex)}
                                                        title="Começar importação a partir desta linha"
                                                    >
                                                        {rowIndex + 1}
                                                    </td>
                                                    {row.map((cell, colIndex) => (
                                                        <td key={colIndex} className="p-2 border-b border-r border-slate-100 dark:border-slate-800 truncate max-w-[200px]" title={cell}>
                                                            {cell}
                                                        </td>
                                                    ))}
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                                {rawRows.length > 50 && (
                                    <div className="p-2 text-center text-[10px] text-slate-400 bg-slate-50 dark:bg-slate-800 border-t border-slate-200 dark:border-slate-700">
                                        Exibindo as primeiras 50 linhas de {rawRows.length}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>

                    {/* Right Panel: Controls (Fixed Width) */}
                    <div className="w-80 bg-white dark:bg-slate-900 border-l border-slate-200 dark:border-slate-700 flex flex-col shrink-0 z-10">
                        <div className="p-5 border-b border-slate-100 dark:border-slate-800">
                            <h4 className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-4">Configuração</h4>

                            <div className="space-y-4">
                                <div>
                                    <label className="block text-[10px] font-bold text-slate-400 mb-1.5 uppercase">Início dos Dados</label>
                                    <div className="flex items-center gap-2">
                                        <button onClick={() => setSkipRowsStart(Math.max(0, skipRowsStart - 1))} className="w-8 h-8 rounded-lg bg-slate-100 dark:bg-slate-800 flex items-center justify-center hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300">-</button>
                                        <div className="flex-1 text-center font-mono font-bold text-slate-700 dark:text-white bg-slate-50 dark:bg-black/20 py-1.5 rounded-lg border border-slate-200 dark:border-slate-800">
                                            Linha {skipRowsStart + 1}
                                        </div>
                                        <button onClick={() => setSkipRowsStart(skipRowsStart + 1)} className="w-8 h-8 rounded-lg bg-slate-100 dark:bg-slate-800 flex items-center justify-center hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300">+</button>
                                    </div>
                                </div>

                                {isPdf && hasRawFile && (
                                    <div>
                                        <label className="block text-[10px] font-bold text-slate-400 mb-1.5 uppercase">Modo de Visualização</label>
                                        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-lg">
                                            <button 
                                                onClick={() => setViewMode('cells')}
                                                className={`flex-1 py-1.5 rounded-md text-[10px] font-bold transition-all ${viewMode === 'cells' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                                            >
                                                Tabela
                                            </button>
                                            <button 
                                                onClick={() => setViewMode('original')}
                                                className={`flex-1 py-1.5 rounded-md text-[10px] font-bold transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                                            >
                                                Original
                                            </button>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="p-5 flex-1 overflow-y-auto">
                            <div className="p-4 bg-amber-50 dark:bg-amber-900/10 rounded-xl border border-amber-100 dark:border-amber-800/50 mb-4">
                                <div className="flex items-start gap-2">
                                    <SparklesIcon className="w-4 h-4 text-amber-500 mt-0.5" />
                                    <div>
                                        <p className="text-xs font-bold text-amber-700 dark:text-amber-400">Dica Inteligente</p>
                                        <p className="text-[10px] text-amber-600 dark:text-amber-500 mt-1 leading-snug">
                                            Clique nos cabeçalhos da tabela para definir o tipo de coluna (Data, Descrição, Valor, Tipo).
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="p-5 border-t border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50">
                            <button
                                onClick={handleSave}
                                disabled={isSavingModel}
                                className="w-full flex items-center justify-center gap-2 py-3 bg-gradient-to-r from-emerald-600 to-teal-500 hover:from-emerald-500 hover:to-teal-400 text-white rounded-xl font-bold text-xs uppercase shadow-lg shadow-emerald-500/20 hover:-translate-y-0.5 transition-all disabled:opacity-70 disabled:cursor-not-allowed"
                            >
                                {isSavingModel ? (
                                    <>
                                        <ArrowPathIcon className="w-4 h-4 animate-spin" />
                                        Salvando...
                                    </>
                                ) : (
                                    <>
                                        <FloppyDiskIcon className="w-4 h-4" />
                                        Salvar e Processar
                                    </>
                                )}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

